        if self.SOURCES is not None:
            SOURCESlist = []
            for i in range(len(self.SOURCES)):
                SOURCESlist.append(builder.CreateString(self.SOURCES[i]))
            SCNReferenceStartSOURCESVector(builder, len(self.SOURCES))
            for i in reversed(range(len(self.SOURCES))):
                builder.PrependUOffsetTRelative(SOURCESlist[i])
            SOURCES = builder.EndVector()
        if self.DATA_MODES is not None:
            DATA_MODESlist = []
